#include <math.h>
#include <limits.h>

#define MAX_PRIME 1000000

typedef struct {
    int prime;
    int count;
} PrimeFactor;

PrimeFactor mp[MAX_PRIME];
int mp_size = 0;

void primeFactor(int a) {
    int i = 2;
    while (i * i <= a) {
        while (a % i == 0) {
            int found = 0;
            for (int j = 0; j < mp_size; j++) {
                if (mp[j].prime == i) {
                    mp[j].count++;
                    found = 1;
                    break;
                }
            }
            if (!found) {
                mp[mp_size].prime = i;
                mp[mp_size].count = 1;
                mp_size++;
            }
            a /= i;
        }
        i++;
    }
    if (a > 1) {
