            if (mp[j].prime == a) {
                mp[j].count++;
                found = 1;
                break;
            }
        }
        if (!found) {
            mp[mp_size].prime = a;
            mp[mp_size].count = 1;
            mp_size++;
        }
    }
}

int trailingZero(int a, int n) {
    int ans = 0;
    while (n > 0) {
        ans += n / a;
        n /= a;
    }
    return ans;
